#include<bits/stdc++.h>
using namespace std;
bool vis[2300010],vis1[2300010];
int s[2300010],f[2300010];
int head[2300010],nxt[30000010],to[30000010],tot;
int in[2300010];
struct node
{
    int a,b,c,d,x,y,op;
};
int h(int a,int b,int c,int d,int x,int y,int op)
{
    return a*200000+b*20000+c*2000+d*200+x*20+y*2+op;
}
int h(node v)
{
    return h(v.a,v.b,v.c,v.d,v.x,v.y,v.op);
}
void add(int x,int y)
{
    to[++tot]=y;
    nxt[tot]=head[x];
    head[x]=tot;
    in[y]++;
}
int r1x,r1y,r2x,r2y,bx,by,n,m;
int dx[4]={0,-1,0,1};
int dy[4]={1,0,-1,0};
char a[21][21];
void bfs()
{
    queue<node> q;
    q.push((node){r1x,r1y,r2x,r2y,bx,by,1});
    vis[h(q.front())]=true;
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        int now=h(t);
        if(t.x==1||(t.x==t.a&&t.y==t.b)||(t.x==t.c&&t.y==t.d))
        {
            continue;
        }
        if(t.op==1)
        {
            for(int i=0;i<4;i++)
            {
                node t1=(node){t.a+dx[i],t.b+dy[i],t.c,t.d,t.x,t.y,0};
                if(t1.a<1||t1.a>n||t1.b<1||t1.b>m||a[t1.a][t1.b]=='#'||(t1.a==t1.c&&t1.b==t1.d))
                {
                    continue;
                }
                int nxt=h(t1);
                add(nxt,now);
                if(!vis[nxt])
                {
                    vis[nxt]=true;
                    q.push(t1);
                }
            }
            for(int i=0;i<4;i++)
            {
                node t1=(node){t.a,t.b,t.c+dx[i],t.d+dy[i],t.x,t.y,0};
                if(t1.c<1||t1.c>n||t1.d<1||t1.d>m||a[t1.c][t1.d]=='#'||(t1.a==t1.c&&t1.b==t1.d))
                {
                    continue;
                }
                int nxt=h(t1);
                add(nxt,now);
                if(!vis[nxt])
                {
                    vis[nxt]=true;
                    q.push(t1);
                }
            }
        }
        else
        {
            for(int i=0;i<3;i++)
            {
                node t1=(node){t.a,t.b,t.c,t.d,t.x+dx[i],t.y+dy[i],1};
                if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||a[t1.x][t1.y]=='#')
                {
                    continue;
                }
                int nxt=h(t1);
                add(nxt,now);
                if(!vis[nxt])
                {
                    vis[nxt]=true;
                    q.push(t1);
                }
            }
        }
    }
}
void topo()
{
    queue<int> q;
    for(int i=1;i<=2300000;i++)
    {
        if(vis[i]&&in[i]==0)
        {
            vis1[i]=true;
            q.push(i);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=nxt[i])
        {
            int v=to[i];
            if(f[t]==0)
            {
                if(!f[v])
                {
                    f[v]=1;
                    s[v]=s[t]+1;
                }
                else
                {
                    s[v]=min(s[v],s[t]+1);
                }
                if(!vis1[v])
                {
                    vis1[v]=true;
                    q.push(v);
                }
            }
            else
            {
                in[v]--;
                if(!f[v])
                {
                    s[v]=max(s[v],s[t]+1);
                }
                if(in[v]==0&&!vis1[v])
                {
                    vis1[v]=true;
                    q.push(v);
                }
            }
        }
    }
}
int main()
{
    int id,t;
    scanf("%d%d",&id,&t);
    while(t--)
    {
        scanf("%d%d",&n,&m);
        memset(vis,0,sizeof(vis));
        memset(in,0,sizeof(in));
        memset(vis1,0,sizeof(vis1));
        memset(f,0,sizeof(f));
        memset(s,0,sizeof(s));
        memset(head,0,sizeof(head));
        r1x=-1;
        for(int i=1;i<=n;i++)
        {
            scanf("%s",a[i]+1);
            for(int j=1;j<=m;j++)
            {
                if(a[i][j]=='X')
                {
                    bx=i;
                    by=j;
                }
                if(a[i][j]=='O')
                {
                    if(r1x==-1)
                    {
                        r1x=i;
                        r1y=j;
                    }
                    else
                    {
                        r2x=i;
                        r2y=j;
                    }
                }
            }
        }
        node st=(node){r1x,r1y,r2x,r2y,bx,by,1};
        bfs();
        topo();
        if(f[h(st)])
        {
            printf("Red %d\n",s[h(st)]);
        }
        else if(vis1[h(st)])
        {
            printf("Black %d\n",s[h(st)]);
        }
        else
        {
            printf("Tie\n");
        }
    }
    return 0;
}
